/**
 * <landi-header> - Shared Lit-based web component for the Landi platform header.
 *
 * Properties:
 *   brand-name  - Text displayed in the top-left (default: "LANDI")
 *   brand-logo  - Optional logo image URL (overrides brand-name text display)
 *   logo-href   - Link target for the logo (default: "/")
 *   user-name   - Authenticated user's display name
 *   user-avatar  - Authenticated user's avatar URL
 *   login-url   - URL for the login link (shown when not logged-in)
 *   logged-in   - Boolean attribute indicating auth state
 *   supabase-url - Supabase project URL (enables client-side auth)
 *   supabase-key - Supabase anon key (enables client-side auth)
 *
 * Slots:
 *   actions     - Additional action buttons placed in the header right side
 * 
 * Events:
 *   landi-auth-change - Dispatched on window when auth state changes
 *     detail: { user: User | null, loggedIn: boolean }
 * 
 * @see {@link ../../README.md|Header Component Documentation}
 */

import { LitElement, html, nothing } from 'lit';
import { style } from './styles';
import { customElement, property, state } from 'lit/decorators.js';
import { createClient, SupabaseClient, User, Session, AuthChangeEvent } from '@supabase/supabase-js';

@customElement('landi-header')
export class LandiHeader extends LitElement {
  @property({ type: String, attribute: 'brand-name' })
  brandName = 'LANDI';

  @property({ type: String, attribute: 'brand-logo' })
  brandLogo = '';

  @property({ type: String, attribute: 'logo-href' })
  logoHref = '/';

  @property({ type: String, attribute: 'user-name' })
  userName = '';

  @property({ type: String, attribute: 'user-avatar' })
  userAvatar = '';

  @property({ type: String, attribute: 'login-url' })
  loginUrl = '/login';

  /** Account/settings link in the user dropdown (host app chooses route). */
  @property({ type: String, attribute: 'account-href' })
  accountHref = '/account';

  @property({ type: Boolean, attribute: 'logged-in', reflect: true })
  loggedIn = false;

  @property({ type: String, attribute: 'supabase-url' })
  supabaseUrl = '';

  @property({ type: String, attribute: 'supabase-key' })
  supabaseKey = '';

  @state() private _user: User | null = null;
  @state() private _menuOpen = false;

  private _supabase: SupabaseClient | null = null;

  static override styles = style();

  override async connectedCallback() {
    super.connectedCallback();

    // Initialize Supabase if credentials provided
    if (this.supabaseUrl && this.supabaseKey) {
      this._supabase = createClient(this.supabaseUrl, this.supabaseKey, {
        auth: {
          persistSession: true,
          autoRefreshToken: true,
          detectSessionInUrl: true,
          storage: {
            getItem: (key) => {
              const name = `${key}=`;
              const decodedCookie = decodeURIComponent(document.cookie);
              const ca = decodedCookie.split(';');
              for (let i = 0; i < ca.length; i++) {
                let c = ca[i];
                while (c.charAt(0) === ' ') {
                  c = c.substring(1);
                }
                if (c.indexOf(name) === 0) {
                  return c.substring(name.length, c.length);
                }
              }
              return null;
            },
            setItem: (key, value) => {
              const domain = window.location.hostname.endsWith('.landi.build') ? '.landi.build' : window.location.hostname;
              const maxAge = 60 * 60 * 24 * 365 * 1000; // 1 year
              document.cookie = `${key}=${encodeURIComponent(value)}; domain=${domain}; path=/; max-age=${maxAge}; reset-site=Lax; secure`;
            },
            removeItem: (key) => {
              const domain = window.location.hostname.endsWith('.landi.build') ? '.landi.build' : window.location.hostname;
              document.cookie = `${key}=; domain=${domain}; path=/; expires=Thu, 01 Jan 1970 00:00:00 GMT; max-age=0`;
            }
          }
        }
      });

      // Check current session
      const { data: { session } } = await this._supabase.auth.getSession();
      if (session?.user) {
        this._user = session.user;
        this.loggedIn = true;
        this.userName = session.user.user_metadata?.full_name || session.user.email?.split('@')[0] || '';
        this.userAvatar = session.user.user_metadata?.avatar_url || '';
      }
      this._broadcastAuthChange();

      // Listen for auth changes (login/logout in other tabs)
      this._supabase.auth.onAuthStateChange((event: AuthChangeEvent, session: Session | null) => {
        this._user = session?.user ?? null;
        this.loggedIn = !!session?.user;
        if (session?.user) {
          this.userName = session.user.user_metadata?.full_name || session.user.email?.split('@')[0] || '';
          this.userAvatar = session.user.user_metadata?.avatar_url || '';
        } else {
          this.userName = '';
          this.userAvatar = '';
        }
        this._broadcastAuthChange();
      });
    }

    // Close dropdown on outside click
    document.addEventListener('click', this._handleOutsideClick);
  }

  override disconnectedCallback() {
    super.disconnectedCallback();
    document.removeEventListener('click', this._handleOutsideClick);
  }

  private _handleOutsideClick = (e: Event) => {
    if (!this.shadowRoot?.contains(e.target as Node)) {
      this._menuOpen = false;
    }
  };

  private _broadcastAuthChange() {
    window.dispatchEvent(new CustomEvent('landi-auth-change', {
      bubbles: true,
      composed: true,
      detail: {
        user: this._user,
        loggedIn: this.loggedIn,
        email: this._user?.email,
        userName: this.userName,
        userAvatar: this.userAvatar,
      }
    }));
  }

  private async _handleSignOut() {
    if (this._supabase) {
      await this._supabase.auth.signOut();
    } else {
      window.dispatchEvent(
        new CustomEvent('landi-header-sign-out', { bubbles: true, composed: true }),
      );
    }
    this._menuOpen = false;
    // Auth state change listener will handle the state update when Supabase is wired
  }

  private _toggleMenu(e: Event) {
    e.stopPropagation();
    this._menuOpen = !this._menuOpen;
  }

  override render() {
    const logoContent = this.brandLogo
      ? html`<img class="logo-img" src=${this.brandLogo} alt=${this.brandName}>`
      : html`
          <div class="logo-icon">
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
              <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8l-6-6z"/>
              <polyline points="14 2 14 8 20 8"/>
              <line x1="16" y1="13" x2="8" y2="13"/>
              <line x1="16" y1="17" x2="8" y2="17"/>
              <polyline points="10 9 9 9 8 9"/>
            </svg>
          </div>
          <div class="brand-text">
            <span class="brand-name">${this.brandName}</span>
            <span class="brand-sub">PLATFORM</span>
          </div>
        `;

    const userSection = this.loggedIn
      ? html`
          <div class="user-menu">
            <button class="user-btn" @click=${this._toggleMenu}>
              ${this.userAvatar
          ? html`<img class="avatar" src=${this.userAvatar} alt=${this.userName}>`
          : html`<div class="avatar-placeholder">${this.userName ? this.userName.charAt(0).toUpperCase() : html`<svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor"><circle cx="12" cy="8" r="4"/><path d="M6 21v-2a4 4 0 0 1 4-4h4a4 4 0 0 1 4 4v2"/></svg>`}</div>`}
            </button>
            ${this._menuOpen ? html`
              <div class="dropdown">
                ${this._user?.email ? html`<div class="user-email">${this._user.email}</div>` : nothing}
                <button class="dropdown-item" @click=${() => { window.location.href = this.accountHref; }}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="8" r="4"/><path d="M6 21v-2a4 4 0 0 1 4-4h4a4 4 0 0 1 4 4v2"/></svg>
                  Account
                </button>
                <div class="dropdown-divider"></div>
                <button class="dropdown-item danger" @click=${this._handleSignOut}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>
                  Sign out
                </button>
              </div>
            ` : nothing}
          </div>
        `
      : html`<a class="login-btn" href=${this.loginUrl}>Log in</a>`;

    return html`
      <nav>
        <a class="logo-link" href=${this.logoHref}>
          ${logoContent}
        </a>
        <div class="right">
          <slot name="actions"></slot>
          ${userSection}
        </div>
      </nav>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'landi-header': LandiHeader;
  }
}

